    public static List<Integer> solve(int l, int r) {
        List<Integer> result = new ArrayList<>();

        for (int i = 1; i < r - l + 1; i++) {
            int temp = l * i;
            if (temp < r) {
                result.add(temp);
            } else {
                break;
            }
        }
        return result;
    }
}

