public class Solution {

    public static boolean solve(int num1, int num2) {
        int count1 = 0;
        int count2 = 0;
        for (int i = 1; i <= num1; i++) {
            if (num1 % i == 0) {
                count1++;
            }
        }
        for (int i = 1; i <= num2; i++) {
            if (num2 % i == 0) {
                count2++;
            }
        }
        if (count1 == count2) {
            return true;
        } else {
            return false;
        }
    }
}

