public class Solution {

    public static boolean solve(int number) {
        int temp = number, sum = 0, lastDigit;
        while (temp != 0) {
            lastDigit = temp % 10;
            sum += Math.pow(lastDigit, 3);
            temp /= 10;
        }
        return number == sum;
    }
}

