public class Solution {

    public static Double solve(int n, int k, Double p) {
        double numerator = 1.0;
        double denominator = 1.0;

        for (int i = k; i > 0; i--) {
            numerator *= (n - i + 1);
            denominator *= i;
        }

        return (numerator * Math.pow(p, k) * Math.pow(1 - p, n - k)) / denominator;
    }
}

