    public static Boolean solve(int[] a, int n, int sum, int count) {
        int length = a.length;
        for (int i = 0; i < length - 2; i++) {
            for (int j = i + 1; j < length - 1; j++) {
                for (int k = j + 1; k < length; k++) {
                    if (a[i] + a[j] + a[k] == sum) {
                        if (count == 0) {
                            return true;
                        } else {
                            count--;
                        }
                    }
                }
            }
        }
        return false;
    }
}

