public class Solution {

    public static int solve(int n, int k) {
        int mod = 1000000007;
        int dp[] = new int[n + 1];
        dp[0] = 1;
        dp[1] = k;
        dp[2] = k * k;
        for (int i = 3; i <= n; i++) {
            dp[i] = ((k - 1) * (dp[i - 1] + dp[i - 2])) % mod;
        }
        return dp[n];
    }
}

