public class Solution {

    public static int solve(int[] arr, int n) {
        if (n == 0) {
            return 0;
        }
        int left = 0, right = n - 1;
        while (left < right) {
            if (arr[left] < arr[right]) {
                return left + 1;
            }
            int mid = (left + right) / 2;
            if (arr[mid] > arr[left]) {
                left = mid;
            } else {
                right = mid;
            }
        }
        return left + 1;
    }
}

