public class Solution {

    public static int solve(String s, int n) {
        int count = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j <= n; j++) {
                String sub = s.substring(i, j);
                int num = 0;
                for (int k = 0; k < sub.length(); k++) {
                    num += sub.charAt(k) - '0';
                }
                if (num == sub.length()) {
                    count++;
                }
            }
        }
        return count;
    }
}

