public class Solution {

    public static int solve(int decinum) {
        int octal = 0;
        int rem = 0;
        int i = 0;
        while (decinum != 0) {
            rem = decinum % 8;
            octal = octal + rem * (int) Math.pow(10, i);
            decinum = decinum / 8;
            i++;
        }
        return octal;
    }
}

