    public static int solve(int n, int m) {
        if (m >= n || n == 0) {
            return 0;
        }
        if (m == 0) {
            return 1;
        }
        return ((n - m) * solve(n - 1, m - 1) + (m + 1) * solve(n - 1, m));
    }
