import java.util.*;


public class Solution {

    public static int[] solve(int n) {
        int[] ludics = new int[n];
        int count = 0;

        for (int i = 1; i <= n; i++) {
            ludics[count++] = i;
        }

        int index = 1;
        while (index < count) {
            int first_ludic = ludics[index];
            int remove_index = index + first_ludic;

            while (remove_index < count) {
                System.arraycopy(ludics, remove_index + 1, ludics, remove_index,
                        count - remove_index - 1);
                count--;
                remove_index += first_ludic - 1;
            }
            index += 1;
        }

        int[] result = Arrays.copyOf(ludics, count);
        return result;
    }
}

