import java.util.*;

public class Solution {

    public static Boolean solve(String str1) {
        Stack<Character> stack = new Stack<>();
        for (int i = 0; i < str1.length(); i++) {
            char ch = str1.charAt(i);
            if (ch == '(' || ch == '{' || ch == '[') {
                stack.push(ch);
            } else if (ch == ')' || ch == '}' || ch == ']') {
                if (stack.isEmpty()) {
                    return false;
                }
                char top = stack.pop();
                if (top == '(' && ch != ')') {
                    return false;
                } else if (top == '{' && ch != '}') {
                    return false;
                } else if (top == '[' && ch != ']') {
                    return false;
                }
            }
        }
        return stack.isEmpty();
    }
}

