public class Solution {

    public static int solve(int[][] tuples) {
        int max = 0;
        for (int[] tuple : tuples) {
            int min = tuple[0];
            for (int value : tuple) {
                if (value < min) {
                    min = value;
                }
            }
            int product = min * tuple[tuple.length - 1];
            if (product > max) {
                max = product;
            }
        }
        return max;
    }
}

