public class Solution {

    public static int solve(int[] coins, int m, int v) {
        if (v == 0) {
            return 0;
        }

        if (v < 0) {
            return Integer.MAX_VALUE;
        }

        int minCoins = Integer.MAX_VALUE;

        for (int i = 0; i < m; i++) {
            int coin = coins[i];
            int remainingValue = v - coin;
            if (remainingValue >= 0) {
                int totalCoins = solve(coins, m, remainingValue);
                if (totalCoins != Integer.MAX_VALUE) {
                    totalCoins += 1;
                }

                if (totalCoins < minCoins) {
                    minCoins = totalCoins;
                }
            }
        }

        return minCoins;
    }
}

