public class Solution {

    public static int solve(int n) {
        int hund1 = n / 100;
        int hund4 = n / 400;
        int leap = n / 4;
        int ordd = n - leap;
        if (hund1 != 0) {
            ordd += hund1;
            leap -= hund1;
        }
        if (hund4 != 0) {
            ordd -= hund4;
            leap += hund4;
        }
        int days = ordd + leap * 2;
        return days % 7;
    }
}

