public class Solution {

    public static int[] solve(int[] nums) {
        int n = nums.length;
        for (int curIdx = n - 1; curIdx > 0; curIdx--) {
            int maxIdx = 0;
            for (int j = 1; j <= curIdx; j++) {
                if (nums[j] > nums[maxIdx]) {
                    maxIdx = j;
                }
            }
            if (maxIdx != curIdx) {
                flip(nums, maxIdx);
                flip(nums, curIdx);
            }
        }
        return nums;
    }

    private static void flip(int[] arr, int k) {
        int start = 0;
        while (start < k) {
            int temp = arr[start];
            arr[start] = arr[k];
            arr[k] = temp;
            start++;
            k--;
        }
    }
}

