import java.util.*;


public class Solution {

    public static int solve(int[] arr, int n, int k) {
        Arrays.sort(arr);
        int left = 0;
        int right = 0;
        int maxRemovals = n;

        while (right < n) {
            while (right < n && arr[right] - arr[left] <= k) {
                right++;
            }
            maxRemovals = Math.min(maxRemovals, n - (right - left));
            left++;
        }

        return maxRemovals;
    }
}

