    public static int[][] solve(int[][] array, int n) {
        int rows = array.length;
        int[][] result = new int[rows][];

        for (int i = 0; i < rows; i++) {
            int cols = array[i].length;
            result[i] = new int[cols - 1];
            int index = 0;
            for (int j = 0; j < cols; j++) {
                if (j != n) {
                    result[i][index++] = array[i][j];
                }
            }
        }
        return result;
    }
}

