public class Solution {

    public static String solve(String text, int n) {
        if (text == null) {
            return null;
        }
        char[] arr = text.toCharArray();
        int len = text.length();
        int count = 0;
        int index = 0;
        while (count < n && index < len) {
            if (arr[index] == ' ' || arr[index] == ',' || arr[index] == '.') {
                arr[index++] = ':';
                count++;
            }
            index++;
        }
        return new String(arr);
    }
}

