public class Solution {

    public static Double solve(int[] data) {
        double mean = 0.0;
        double sum = 0.0;

        for (int i = 0; i < data.length; i++) {
            sum += data[i];
        }

        mean = sum / data.length;
        double sd = 0.0;

        for (int i = 0; i < data.length; i++) {
            sd += Math.pow(data[i] - mean, 2);
        }

        sd = Math.sqrt(sd / (data.length - 1));
        return sd;
    }
}

