public class Solution {

    public static String solve(String[] input) {
        int[] counts = new int[input.length];
        String[] uniqueStrings = new String[input.length];
        int uniqueCount = 0;

        for (int i = 0; i < input.length; i++) {
            int count = 1;
            boolean found = false;

            for (int j = 0; j < uniqueCount; j++) {
                if (uniqueStrings[j].equals(input[i])) {
                    found = true;
                    break;
                }
            }

            if (!found) {
                uniqueStrings[uniqueCount] = input[i];
                uniqueCount++;

                for (int j = i + 1; j < input.length; j++) {
                    if (input[j].equals(input[i])) {
                        count++;
                    }
                }
                counts[i] = count;
            } else {
                counts[i] = -1;
            }
        }

        int max = 0;
        int secondMax = 0;

        for (int i = 0; i < counts.length; i++) {
            if (counts[i] > max) {
                secondMax = max;
                max = counts[i];
            } else if (counts[i] > secondMax && counts[i] != max) {
                secondMax = counts[i];
            }
        }

        for (int i = 0; i < counts.length; i++) {
            if (counts[i] == secondMax) {
                return input[i];
            }
        }
        return null;
    }
}

