public class Solution {

    public static int[] solve(int[] myArray) {
        int n = myArray.length;
        int h = 1;
        while (h < n / 3) {
            h = 3 * h + 1;
        }
        while (h >= 1) {
            for (int i = h; i < n; i++) {
                for (int j = i; j >= h && myArray[j - h] > myArray[j]; j -= h) {
                    int temp = myArray[j];
                    myArray[j] = myArray[j - h];
                    myArray[j - h] = temp;
                }
            }
            h = h / 3;
        }
        return myArray;
    }
}

