public class Solution {

    public static int solve(int n) {
        if (n <= 2) {
            return n;
        }
        int i = n * 2;
        int factors[] = new int[n];
        for (int j = 0; j < n; j++) {
            factors[j] = j + 1;
        }
        while (true) {
            for (int a = 0; a < n; a++) {
                if (i % factors[a] != 0) {
                    i += n;
                    break;
                }
                if (factors[a] == factors[n - 1] && i % factors[a] == 0) {
                    return i;
                }
            }
        }
    }
}

