public class Solution {

    public static int solve(String x, String y, int m, int n) {
        if (m == 0) {
            return n;
        }
        if (n == 0) {
            return m;
        }
        if (x.charAt(m - 1) == y.charAt(n - 1)) {
            return 1 + solve(x, y, m - 1, n - 1);
        }
        return 1 + Math.min(solve(x, y, m - 1, n), solve(x, y, m, n - 1));
    }
}

