public class Solution {

    public static Double solve(int n) {
        double[] dp = new double[n + 1];
        dp[1] = 1;
        for (int i = 2; i <= n; i++) {
            dp[i] = dp[i - 1] + (i * (i + 1)) / 2;
        }
        return dp[n];
    }
}

